type Sign = Neg | Zero | Pos;
fn label(s: Sign) => Ternary{1} = match s { Neg => 0t-, Zero => 0t0, _ => 0t+ };
fn main() => Ternary{1} = label(Zero);" , fragment : Fragment :: Data , note : "a flat non-recursive data match returning a repr — a data case the compiled \
                   backends MAY still lower (measured, not assumed)" , } , Case { id : "data-construct" , src : "nodule d;
type Nat = Z | S(Nat);
fn main() => Nat = S(S(Z));" , fragment : Fragment :: Data , note : "a datum result (the program evaluates to constructed data)" , } , Case { id : "data-nested-match" , src : "nodule d;
type Nat = Z | S(Nat);
fn pred2(n: Nat) => Nat = match n { Z => Z, S(Z) => Z, S(S(m)) => m };
fn main() => Nat = pred2(S(S(S(Z))));" , fragment : Fragment :: Data , note : "nested (Maranget) patterns returning a datum" , } , Case { id : "rec-self" , src : "nodule d;
type Nat = Z | S(Nat);
fn drop_(n: Nat) => Nat = match n { Z => Z, S(m) => drop_(m) };
fn main() => Nat = drop_(S(S(S(Z))));" , fragment : Fragment :: Recursion , note : "self-recursion consuming a Nat (Fix + App + Match)" , } , Case { id : "rec-build" , src : "nodule d;
type Nat = Z | S(Nat);
fn copy(n: Nat) => Nat = match n { Z => Z, S(m) => S(copy(m)) };
fn main() => Nat = copy(S(S(Z)));" , fragment : Fragment :: Recursion , note : "self-recursion building data on the way back" , } , Case { id : "rec-mutual" , src : "nodule d;
type Nat = Z | S(Nat);
fn ping(n: Nat) => Nat = match n { Z => Z, S(m) => pong(m) };
