# [doc = " Measure one case's scaling curve on one backend, across `1..=max_workers` OS threads."] # [doc = ""] # [doc = " A single probe run first decides *whether* this (case, backend) pair is even measurable"] # [doc = " (matches the single-core harness's own probe-before-time discipline in"] # [doc = " [`crate::backend::warm_runner`]): a `Skipped`/`Unlowerable`/`Error` probe short-circuits to the"] # [doc = " corresponding never-silent [`ScalingOutcome`] variant with no batch timing attempted."] # [must_use] pub fn measure_case_scaling (case : & Case , backend : Backend , max_workers : usize , batch_size : u32 , repeats : u32 ,) -> ScalingPoint { let max_workers = max_workers . max (1) ; let node = case . elaborate () . unwrap_or_else (| e | panic ! ("corpus case `{}` failed to elaborate: {e}" , case . id)) ; let eng = Engines :: default () ; let probe = run_once (backend , & node , & eng) ; let outcome = match & probe { Outcome :: Skipped (reason) => ScalingOutcome :: Skipped (reason . clone ()) , Outcome :: Unlowerable (reason) => ScalingOutcome :: Unmeasurable (reason . clone ()) , Outcome :: Error (reason) => ScalingOutcome :: Unmeasurable (format ! ("runtime error on the single-job probe (not a capability boundary, but no batch was \
             attempted): {reason}")) , Outcome :: Value (_) => { let samples : Vec < ScalingSample > = (1 ..= max_workers) . filter_map (| w | time_batch (case . src , backend , w , batch_size , repeats)) . collect () ; if samples . is_empty () { ScalingOutcome :: Unmeasurable ("single-job probe produced a value but no scaling batch did (non-deterministic \
                     or environment-sensitive outcome) — recorded, not hidden" . to_string () ,) } else { ScalingOutcome :: Measured (samples) } } } ; ScalingPoint { case_id : case . id . to_string () , backend , batch_size , repeats , outcome , } }
